+
+        // Record cell delta
+        let cell_key = CellKey {
+            btree: BtreeRef::Table(TableId::new(3)),
+            kind: SemanticKeyKind::TableRow,
+            key_digest: [2u8; 16],
+        };
+        let idx = mgr
+            .cell_log()
+            .record_insert(cell_key, pgno, vec![9, 10, 11, 12], txn.token());
